import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { updateUser, uploadProfileImage } from '../supabase/db';
import TopBar from '../components/layout/TopBar';
import BottomNav from '../components/layout/BottomNav';

export default function ProfilePage() {
  const { user, refreshUser } = useAuth();
  const navigate = useNavigate();
  const fileRef  = useRef();

  const [name,         setName]         = useState(user?.name || '');
  const [phone,        setPhone]        = useState(user?.phone || '');
  const [address,      setAddress]      = useState(user?.address || '');
  const [addressDetail, setAddressDetail] = useState(user?.addressDetail || '');
  const [deliveryMemo, setDeliveryMemo] = useState(user?.deliveryMemo || '');
  const [profileImage, setProfileImage] = useState(user?.profileImage || null);
  const [uploading,    setUploading]    = useState(false);
  const [saving,       setSaving]       = useState(false);

  // 프로필 이미지 업로드
  const handleImageChange = async (e) => {
    const file = e.target.files[0];
    if (!file || !user?.id) return;
    setUploading(true);
    try {
      const url = await uploadProfileImage(user.id, file);
      setProfileImage(url);
    } catch (e) { console.error(e); }
    finally { setUploading(false); }
  };

  // 행정안전부 주소 검색 팝업 (Daum Postcode)
  const openAddressSearch = () => {
    if (!window.daum?.Postcode) {
      // 스크립트 동적 로드
      const script = document.createElement('script');
      script.src = '//t1.daumcdn.net/mapjsapi/bundle/postcode/prod/postcode.v2.js';
      script.onload = () => openDaumPostcode();
      document.head.appendChild(script);
    } else {
      openDaumPostcode();
    }
  };

  const openDaumPostcode = () => {
    new window.daum.Postcode({
      oncomplete: (data) => {
        setAddress(data.roadAddress || data.jibunAddress);
      },
      theme: { bgColor: '#fefae0', searchBgColor: '#ccd5ae', outlineColor: '#d4a373' },
    }).open();
  };

  const handleSave = async () => {
    if (!user?.id) return;
    setSaving(true);
    try {
      const updated = { name, phone, address, addressDetail, deliveryMemo, profileImage };
      await updateUser(user.id, updated);
      refreshUser(updated);
      navigate(-1);
    } catch (e) { console.error(e); }
    finally { setSaving(false); }
  };

  return (
    <div className="page">
      <TopBar title="프로필 설정" showBack />
      <div className="page-content fade-in">

        {/* 프로필 이미지 */}
        <div style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          padding: '18px 0 20px',
        }}>
          <div
            onClick={() => fileRef.current?.click()}
            style={{
              width: 72, height: 72, borderRadius: '50%',
              background: 'var(--bg-surface-secondary)',
              border: '2px solid var(--accent-primary)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              cursor: 'pointer', overflow: 'hidden', position: 'relative',
            }}
          >
            {profileImage ? (
              <img src={profileImage} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            ) : (
              <svg width="30" height="30" viewBox="0 0 30 30" fill="none">
                <circle cx="15" cy="12" r="5.5" stroke="var(--accent-primary)" strokeWidth="1.5"/>
                <path d="M5 27c0-5.5 4.5-10 10-10s10 4.5 10 10"
                  stroke="var(--accent-primary)" strokeWidth="1.5" fill="none"/>
              </svg>
            )}
            {/* 편집 아이콘 오버레이 */}
            <div style={{
              position: 'absolute', bottom: 0, right: 0,
              width: 22, height: 22, borderRadius: '50%',
              background: 'var(--accent-primary)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}>
              <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
                <path d="M1 9l2-2 5.5-5.5L7 0 1.5 5.5 0 9h1z" fill="#fff"/>
              </svg>
            </div>
          </div>
          {uploading && (
            <div style={{ fontSize: 11, color: 'var(--text-tertiary)', marginTop: 6 }}>업로드 중...</div>
          )}
          <input ref={fileRef} type="file" accept="image/*" onChange={handleImageChange} style={{ display: 'none' }} />
        </div>

        {/* 폼 */}
        <div style={{
          background: 'var(--bg-surface)',
          borderRadius: 'var(--radius-lg)',
          border: '0.5px solid var(--border-default)',
          overflow: 'hidden',
          marginBottom: 12,
        }}>
          <FormField label="이름 변경" value={name} onChange={setName} placeholder="이름" />
          <div style={{ height: '0.5px', background: 'var(--border-default)' }} />
          <FormField label="전화번호" value={phone} onChange={setPhone} placeholder="010-0000-0000" type="tel" />
          <div style={{ height: '0.5px', background: 'var(--border-default)' }} />

          {/* 주소 (팝업 검색) */}
          <div style={{ padding: '10px 13px' }}>
            <div style={{ fontSize: 12, color: 'var(--text-tertiary)', marginBottom: 5 }}>주소 변경</div>
            <div style={{ display: 'flex', gap: 6, marginBottom: 6 }}>
              <div style={{
                flex: 1, height: 38, borderRadius: 'var(--radius-sm)',
                border: '0.5px solid var(--border-input)',
                background: 'var(--bg-surface-secondary)',
                padding: '0 10px',
                display: 'flex', alignItems: 'center',
                fontSize: 12, color: address ? 'var(--text-primary)' : 'var(--text-hint)',
              }}>
                {address || '주소를 검색해 주세요'}
              </div>
              <button
                onClick={openAddressSearch}
                style={{
                  height: 38, padding: '0 12px',
                  borderRadius: 'var(--radius-sm)',
                  background: 'var(--accent-green)',
                  border: '0.5px solid var(--border-default)',
                  fontSize: 12, color: 'var(--accent-green-dark)',
                  cursor: 'pointer', fontFamily: 'var(--font-sans)', whiteSpace: 'nowrap',
                }}
              >
                검색
              </button>
            </div>
            <input
              type="text"
              value={addressDetail}
              onChange={e => setAddressDetail(e.target.value)}
              placeholder="상세 주소 (동, 호수 등)"
              style={{
                width: '100%', height: 38,
                borderRadius: 'var(--radius-sm)',
                border: '0.5px solid var(--border-input)',
                background: 'var(--bg-input)',
                padding: '0 10px',
                fontSize: 12, color: 'var(--text-primary)',
              }}
            />
          </div>
          <div style={{ height: '0.5px', background: 'var(--border-default)' }} />

          {/* 배송 메모 */}
          <div style={{ padding: '10px 13px' }}>
            <div style={{ fontSize: 12, color: 'var(--text-tertiary)', marginBottom: 5 }}>배송 메모</div>
            <textarea
              value={deliveryMemo}
              onChange={e => setDeliveryMemo(e.target.value)}
              placeholder="예: 부재 시 경비실 맡겨주세요"
              rows={3}
              style={{
                width: '100%',
                borderRadius: 'var(--radius-sm)',
                border: '0.5px solid var(--border-input)',
                background: 'var(--bg-input)',
                padding: '8px 10px',
                fontSize: 12, color: 'var(--text-primary)',
                resize: 'none', lineHeight: 1.6,
                fontFamily: 'var(--font-sans)',
              }}
            />
          </div>
        </div>

        {/* 저장 버튼 */}
        <button
          onClick={handleSave}
          disabled={saving}
          style={{
            width: '100%', height: 44,
            borderRadius: 'var(--radius-md)',
            background: saving ? 'var(--border-strong)' : 'var(--accent-primary)',
            border: 'none', color: '#fff',
            fontSize: 14, fontWeight: 500,
            cursor: 'pointer', fontFamily: 'var(--font-sans)',
            transition: 'background var(--transition-fast)',
          }}
        >
          {saving ? '저장 중...' : '저장하기'}
        </button>

        <div style={{ height: 20 }} />
      </div>
      <BottomNav />
    </div>
  );
}

function FormField({ label, value, onChange, placeholder, type = 'text' }) {
  return (
    <div style={{ padding: '10px 13px' }}>
      <div style={{ fontSize: 12, color: 'var(--text-tertiary)', marginBottom: 5 }}>{label}</div>
      <input
        type={type}
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: '100%', height: 38,
          borderRadius: 'var(--radius-sm)',
          border: '0.5px solid var(--border-input)',
          background: 'var(--bg-input)',
          padding: '0 10px',
          fontSize: 12, color: 'var(--text-primary)',
        }}
      />
    </div>
  );
}
